package mpdc4gsr.core.monitoring

import android.os.SystemClock
import mpdc4gsr.core.utils.AppLogger
import java.util.concurrent.ConcurrentHashMap
import java.util.concurrent.atomic.AtomicLong

object PerformanceMetrics {
    private const val TAG = "PerformanceMetrics"
    private val startTimes = ConcurrentHashMap<String, Long>()
    private val metrics = ConcurrentHashMap<String, AtomicLong>()

    fun initialize() {
        val appStartTime = SystemClock.elapsedRealtime()
        startTimes["app_cold_start"] = appStartTime
        AppLogger.d(TAG, "Performance metrics initialized")
    }

    fun startMeasurement(operationName: String) {
        startTimes[operationName] = SystemClock.elapsedRealtime()
    }

    fun endMeasurement(operationName: String): Long {
        val startTime = startTimes.remove(operationName) ?: return -1
        val duration = SystemClock.elapsedRealtime() - startTime
        logMetric(operationName, duration)
        return duration
    }

    fun logMetric(metricName: String, value: Long) {
        AppLogger.i(TAG, "Metric: $metricName = $value ms")
        // TODO: Send to analytics backend
    }

    fun incrementCounter(counterName: String) {
        metrics.getOrPut(counterName) { AtomicLong(0) }.incrementAndGet()
    }

    fun getCounter(counterName: String): Long {
        return metrics[counterName]?.get() ?: 0
    }

    fun recordColdStartComplete() {
        val duration = endMeasurement("app_cold_start")
        if (duration > 0) {
            AppLogger.i(TAG, "Cold start completed in $duration ms (target: < 2000 ms)")
            if (duration > 2000) {
                AppLogger.w(TAG, "Cold start exceeded target of 2000ms")
            }
        }
    }

    fun recordFrameTime(frameTimeNanos: Long) {
        val frameTimeMs = frameTimeNanos / 1_000_000
        if (frameTimeMs > 16) {
            incrementCounter("janky_frames")
            if (frameTimeMs > 32) {
                AppLogger.w(TAG, "Severe frame jank detected: ${frameTimeMs}ms")
            }
        }
        incrementCounter("total_frames")
    }

    fun getJankyFramePercentage(): Float {
        val totalFrames = getCounter("total_frames")
        if (totalFrames == 0L) return 0f
        val jankyFrames = getCounter("janky_frames")
        return (jankyFrames.toFloat() / totalFrames) * 100
    }

    fun logSummary() {
        AppLogger.i(TAG, "=== Performance Metrics Summary ===")
        AppLogger.i(TAG, "Total frames: ${getCounter("total_frames")}")
        AppLogger.i(
            TAG,
            "Janky frames: ${getCounter("janky_frames")} (${String.format("%.2f", getJankyFramePercentage())}%)"
        )
        AppLogger.i(TAG, "Recording sessions: ${getCounter("recording_sessions")}")
        AppLogger.i(TAG, "Successful recordings: ${getCounter("successful_recordings")}")
        AppLogger.i(TAG, "Failed recordings: ${getCounter("failed_recordings")}")
        AppLogger.i(TAG, "===================================")
    }

    fun reset() {
        startTimes.clear()
        metrics.clear()
        AppLogger.d(TAG, "All metrics reset")
    }
}

inline fun <T> measureTime(operationName: String, block: () -> T): T {
    PerformanceMetrics.startMeasurement(operationName)
    try {
        return block()
    } finally {
        PerformanceMetrics.endMeasurement(operationName)
    }
}

suspend inline fun <T> measureTimeSuspend(operationName: String, crossinline block: suspend () -> T): T {
    PerformanceMetrics.startMeasurement(operationName)
    try {
        return block()
    } finally {
        PerformanceMetrics.endMeasurement(operationName)
    }
}


// ===== FROM: app\src\main\java\mpdc4gsr\core\monitoring\TelemetryManager.kt =====

package mpdc4gsr.core.monitoring

import android.content.Context
import android.os.Build
import mpdc4gsr.core.utils.AppLogger
import org.json.JSONObject
import java.util.concurrent.ConcurrentHashMap

object TelemetryManager {
    private const val TAG = "TelemetryManager"
    private var isInitialized = false
    private var userId: String? = null
    private var sessionId: String? = null
    private val properties = ConcurrentHashMap<String, String>()

    fun initialize(context: Context) {
        if (isInitialized) {
            AppLogger.w(TAG, "TelemetryManager already initialized")
            return
        }
        try {
            sessionId = generateSessionId()
            setDeviceProperties(context)
            isInitialized = true
            AppLogger.i(TAG, "TelemetryManager initialized successfully")
        } catch (e: Exception) {
            AppLogger.e(TAG, "Failed to initialize TelemetryManager", e)
        }
    }

    fun setUserId(id: String) {
        userId = id
        AppLogger.d(TAG, "User ID set")
    }

    fun clearUserId() {
        userId = null
        AppLogger.d(TAG, "User ID cleared")
    }

    fun trackEvent(eventName: String, params: Map<String, Any>? = null) {
        if (!isInitialized) {
            AppLogger.w(TAG, "TelemetryManager not initialized")
            return
        }
        try {
            val eventData = buildEventData(eventName, params)
            AppLogger.i(TAG, "Event tracked: $eventName")
            // TODO: Send to analytics backend
        } catch (e: Exception) {
            AppLogger.e(TAG, "Failed to track event: $eventName", e)
        }
    }

    fun trackScreenView(screenName: String, screenClass: String) {
        trackEvent(
            "screen_view", mapOf(
                "screen_name" to screenName,
                "screen_class" to screenClass
            )
        )
    }

    fun trackError(error: String, exception: Throwable? = null, fatal: Boolean = false) {
        try {
            AppLogger.e(TAG, "Error tracked: $error", exception)
            val errorData = mapOf(
                "error" to error,
                "fatal" to fatal,
                "exception_type" to (exception?.javaClass?.simpleName ?: "Unknown"),
                "stack_trace" to (exception?.stackTraceToString() ?: "")
            )
            trackEvent(if (fatal) "fatal_error" else "error", errorData)
            // TODO: Send to crash reporting service
        } catch (e: Exception) {
            AppLogger.e(TAG, "Failed to track error", e)
        }
    }

    fun logMetric(metricName: String, value: Number, unit: String? = null) {
        try {
            AppLogger.i(TAG, "Metric: $metricName = $value${unit?.let { " $it" } ?: ""}")
            val metricData = mutableMapOf<String, Any>(
                "metric_name" to metricName,
                "value" to value
            )
            unit?.let { metricData["unit"] = it }
            trackEvent("metric_logged", metricData)
            // TODO: Send to metrics backend
        } catch (e: Exception) {
            AppLogger.e(TAG, "Failed to log metric: $metricName", e)
        }
    }

    fun trackRecordingSession(recordingId: String, durationMs: Long, success: Boolean) {
        trackEvent(
            "recording_session", mapOf(
                "recording_id" to recordingId,
                "duration_ms" to durationMs,
                "duration_seconds" to (durationMs / 1000),
                "success" to success
            )
        )
    }

    fun trackFeatureUsage(featureName: String, action: String) {
        trackEvent(
            "feature_usage", mapOf(
                "feature" to featureName,
                "action" to action
            )
        )
    }

    fun trackNetworkRequest(
        endpoint: String,
        method: String,
        statusCode: Int,
        durationMs: Long
    ) {
        trackEvent(
            "network_request", mapOf(
                "endpoint" to endpoint,
                "method" to method,
                "status_code" to statusCode,
                "duration_ms" to durationMs,
                "success" to (statusCode in 200..299)
            )
        )
    }

    fun trackPermissionRequest(permission: String, granted: Boolean) {
        trackEvent(
            "permission_request", mapOf(
                "permission" to permission,
                "granted" to granted
            )
        )
    }

    fun setProperty(key: String, value: String) {
        properties[key] = value
    }

    fun removeProperty(key: String) {
        properties.remove(key)
    }

    private fun buildEventData(eventName: String, params: Map<String, Any>?): JSONObject {
        return JSONObject().apply {
            put("event_name", eventName)
            put("timestamp", System.currentTimeMillis())
            put("session_id", sessionId)
            userId?.let { put("user_id", it) }
            properties.forEach { (key, value) ->
                put(key, value)
            }
            params?.forEach { (key, value) ->
                put(key, value)
            }
        }
    }

    private fun setDeviceProperties(context: Context) {
        setProperty("device_model", Build.MODEL)
        setProperty("device_manufacturer", Build.MANUFACTURER)
        setProperty("android_version", Build.VERSION.RELEASE)
        setProperty("sdk_version", Build.VERSION.SDK_INT.toString())
        setProperty("app_version", getAppVersion(context))
    }

    private fun getAppVersion(context: Context): String {
        return try {
            val packageInfo = context.packageManager.getPackageInfo(context.packageName, 0)
            packageInfo.versionName ?: "Unknown"
        } catch (e: Exception) {
            "Unknown"
        }
    }

    private fun generateSessionId(): String {
        return "session_${System.currentTimeMillis()}_${java.util.UUID.randomUUID().toString().substring(0, 8)}"
    }
}


inline fun <T> trackExecutionTime(operationName: String, block: () -> T): T {
    val startTime = System.currentTimeMillis()
    try {
        return block()
    } finally {
        val duration = System.currentTimeMillis() - startTime
        TelemetryManager.logMetric("${operationName}_duration", duration, "ms")
    }
}

suspend inline fun <T> trackExecutionTimeSuspend(
    operationName: String,
    crossinline block: suspend () -> T
): T {
    val startTime = System.currentTimeMillis()
    try {
        return block()
    } finally {
        val duration = System.currentTimeMillis() - startTime
        TelemetryManager.logMetric("${operationName}_duration", duration, "ms")
    }
}


