) {
    companion object {
        fun fromShimmerData(
            value: Float,
            battery: Int,
            connected: Boolean
        ): ComposeGSRData {
            return ComposeGSRData(
                currentValue = value,
                batteryLevel = battery,
                connectionState = if (connected) "Connected" else "Disconnected"
            )
        }
    }
}

data class ComposeConnectionStates(
