                    onClick = { onModeChange(CameraMode.DUAL_VIEW) },
                    modifier = Modifier.weight(1f)
                )
                CameraModeChip(
                    mode = CameraMode.OVERLAY,
                    label = "Overlay",
                    selected = selectedMode == CameraMode.OVERLAY,
                    onClick = { onModeChange(CameraMode.OVERLAY) },
                    modifier = Modifier.weight(1f)
                )
            }
        }
    }
}

