@Composable
private fun DualCameraPreviewCard(
    mode: CameraMode,
    rgbActive: Boolean,
    thermalActive: Boolean,
    syncEnabled: Boolean
) {
    Card(
        modifier = Modifier.fillMaxWidth(),
        elevation = CardDefaults.cardElevation(defaultElevation = 4.dp)
    ) {
        Column(
            modifier = Modifier.padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(12.dp)
        ) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Text(
                    "Camera Preview",
                    style = MaterialTheme.typography.headlineSmall,
                    fontWeight = FontWeight.Bold
                )
                if (syncEnabled) {
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(4.dp)
                    ) {
                        Icon(
                            Icons.Default.Sync,
                            contentDescription = "Synced",
                            tint = MaterialTheme.colorScheme.primary,
                            modifier = Modifier.size(16.dp)
                        )
                        Text(
                            "Synced",
                            style = MaterialTheme.typography.bodySmall,
                            color = MaterialTheme.colorScheme.primary
                        )
                    }
                }
            }
            // Preview area based on mode
            when (mode) {
                CameraMode.RGB_ONLY -> {
                    RGBPreviewArea(active = rgbActive)
                }

                CameraMode.THERMAL_ONLY -> {
                    ThermalPreviewArea(active = thermalActive)
                }

                CameraMode.DUAL_VIEW -> {
                    DualViewPreviewArea(
                        rgbActive = rgbActive,
                        thermalActive = thermalActive
                    )
                }

                CameraMode.OVERLAY -> {
                    OverlayPreviewArea(
                        rgbActive = rgbActive,
                        thermalActive = thermalActive
                    )
                }
            }
        }
    }
}

