enum class AnalysisType(val displayName: String) {
    RAW_SIGNAL("Raw"),
    FILTERED("Filtered"),
    FEATURES("Features"),
    STATISTICS("Stats")
}

private fun generateSampleGSRData(): List<Float> {
    return (0..200).map { i ->
        0.5f + 0.3f * sin(i * 0.1).toFloat() + 0.1f * Random.nextFloat()
    }
}

