    @OptIn(ExperimentalMaterial3Api::class)
    @Composable
    override fun Content(viewModel: GSRPlotViewModel) {
        val sessionId = intent.getStringExtra(EXTRA_SESSION_ID) ?: "unknown"
        val dataPath = intent.getStringExtra(EXTRA_DATA_PATH)
