@Composable
private fun GSRVideoPlayerContent(
    videoPath: String,
    sessionId: String?,
    modifier: Modifier = Modifier
) {
    var isPlaying by remember { mutableStateOf(false) }
    var currentPosition by remember { mutableFloatStateOf(0f) }
    var duration by remember { mutableFloatStateOf(100f) }
    var showDataOverlay by remember { mutableStateOf(true) }
    var playbackSpeed by remember { mutableFloatStateOf(1.0f) }
    Column(
        modifier = modifier.fillMaxSize()
    ) {
        // Video Player Area
        VideoPlayerCard(
            videoPath = videoPath,
            isPlaying = isPlaying,
            currentPosition = currentPosition,
            duration = duration,
            showDataOverlay = showDataOverlay,
            onPlayPause = { isPlaying = !isPlaying },
            onSeek = { currentPosition = it }
        )
        // Scrollable content below video
        Column(
            modifier = Modifier
                .fillMaxSize()
                .verticalScroll(rememberScrollState())
                .padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            // Video Controls
            VideoControlsCard(
                isPlaying = isPlaying,
                currentPosition = currentPosition,
                duration = duration,
                playbackSpeed = playbackSpeed,
                showDataOverlay = showDataOverlay,
                onPlayPause = { isPlaying = !isPlaying },
                onSeek = { currentPosition = it },
                onSpeedChange = { playbackSpeed = it },
                onOverlayToggle = { showDataOverlay = it }
            )
            // Video Information
            VideoInfoCard(
                videoPath = videoPath,
                sessionId = sessionId,
                duration = duration
            )
            // GSR Data Timeline
            if (sessionId != null) {
                GSRDataTimelineCard(
                    sessionId = sessionId,
                    currentPosition = currentPosition,
                    duration = duration
                )
            }
            // Playback Statistics
            PlaybackStatisticsCard(
                currentPosition = currentPosition,
                duration = duration,
                playbackSpeed = playbackSpeed
            )
            // Export Options
            VideoExportCard(
                videoPath = videoPath,
                sessionId = sessionId
            )
        }
    }
}

@Composable
private fun VideoPlayerCard(
    videoPath: String,
    isPlaying: Boolean,
    currentPosition: Float,
    duration: Float,
    showDataOverlay: Boolean,
    onPlayPause: () -> Unit,
    onSeek: (Float) -> Unit
) {
    Card(
        modifier = Modifier
            .fillMaxWidth()
            .padding(16.dp),
        elevation = CardDefaults.cardElevation(defaultElevation = 4.dp)
    ) {
        Column(
            modifier = Modifier.padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(12.dp)
        ) {
            Text(
                "Video Playback",
                style = MaterialTheme.typography.headlineSmall,
                fontWeight = FontWeight.Bold
            )
            // Video View Container
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .height(250.dp)
                    .background(
                        Color.Black,
                        RoundedCornerShape(8.dp)
                    ),
                contentAlignment = Alignment.Center
            ) {
                // AndroidView for VideoView integration
                AndroidView(
                    factory = { context ->
                        VideoView(context).apply {
                            setVideoURI(Uri.parse(videoPath))
                            setMediaController(MediaController(context))
                        }
                    },
                    modifier = Modifier.fillMaxSize()
                )
                // GSR Data Overlay
                if (showDataOverlay) {
                    GSRDataOverlay(
                        currentPosition = currentPosition,
                        modifier = Modifier.align(Alignment.TopEnd)
                    )
                }
                // Play/Pause Overlay
                IconButton(
                    onClick = onPlayPause,
                    modifier = Modifier
                        .align(Alignment.Center)
                        .size(64.dp)
                        .background(
                            Color.Black.copy(alpha = 0.6f),
                            RoundedCornerShape(32.dp)
                        )
                ) {
                    Icon(
                        if (isPlaying) Icons.Default.Pause else Icons.Default.PlayArrow,
                        contentDescription = if (isPlaying) "Pause" else "Play",
                        tint = Color.White,
                        modifier = Modifier.size(32.dp)
                    )
                }
            }
            // Seek Bar
            Column {
                Slider(
                    value = currentPosition,
                    onValueChange = onSeek,
                    valueRange = 0f..duration,
                    modifier = Modifier.fillMaxWidth()
                )
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween
                ) {
                    Text(
                        formatTime(currentPosition),
                        style = MaterialTheme.typography.bodySmall
                    )
                    Text(
                        formatTime(duration),
                        style = MaterialTheme.typography.bodySmall
                    )
                }
            }
        }
    }
}

@Composable
private fun GSRDataOverlay(
