@Composable
fun GSRVideoPlayerScreen(
    videoUri: String = "sample_video.mp4",
    sessionId: String = "GSR_Session_001",
    onBackClick: (() -> Unit)? = null,
    modifier: Modifier = Modifier
) {
    val localContext = LocalContext.current
    var isPlaying by remember { mutableStateOf(false) }
    var currentPosition by remember { mutableStateOf(0) }
    var duration by remember { mutableStateOf(100) }
    var showGSROverlay by remember { mutableStateOf(true) }
    Column(
        modifier = modifier
            .fillMaxSize()
            .background(Color(0xFF16131e))
    ) {
        TitleBar(
            title = "GSR Video Player",
            showBackButton = true,
            onBackClick = onBackClick
        ) {
            TitleBarAction(
                icon = Icons.Default.Visibility,
                contentDescription = "Toggle GSR Overlay",
                onClick = { showGSROverlay = !showGSROverlay }
            )
        }
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            // Video Player Section
            Card(
                modifier = Modifier
                    .fillMaxWidth()
                    .aspectRatio(16f / 9f),
                colors = CardDefaults.cardColors(containerColor = Color(0xFF2A2A2A))
            ) {
                Box(
                    modifier = Modifier.fillMaxSize()
                ) {
                    // Video View
                    AndroidView(
                        factory = { context ->
                            VideoView(context).apply {
                                // In real implementation, set video URI and controls
                                // setVideoURI(Uri.parse(videoUri))
                            }
                        },
                        modifier = Modifier.fillMaxSize()
                    )
                    // GSR Data Overlay
                    if (showGSROverlay) {
                        GSRDataOverlay(
                            modifier = Modifier.align(Alignment.BottomEnd)
                        )
                    }
                    // Play/Pause Button
                    FloatingActionButton(
                        onClick = { isPlaying = !isPlaying },
                        modifier = Modifier.align(Alignment.Center),
                        containerColor = MaterialTheme.colorScheme.primary.copy(alpha = 0.8f)
                    ) {
                        Icon(
                            imageVector = if (isPlaying) Icons.Default.Pause else Icons.Default.PlayArrow,
                            contentDescription = if (isPlaying) "Pause" else "Play",
                            tint = Color.White
                        )
                    }
                }
            }
            // Video Controls
            VideoControlsCard(
                isPlaying = isPlaying,
                currentPosition = currentPosition,
                duration = duration,
                onPlayPause = { isPlaying = !isPlaying },
                onSeek = { currentPosition = it }
            )
            // Session Information
            SessionDetailsCard(sessionId = sessionId)
            // GSR Metrics
            GSRMetricsCard()
        }
    }
}

