                                    "Exporting session...",
                                    android.widget.Toast.LENGTH_SHORT
                                ).show()
                            }) {
                                Icon(Icons.Default.FileDownload, contentDescription = "Export")
                            }
                        }
                    )
                }
            ) { paddingValues ->
                SessionDetailContent(
                    sessionId = sessionId,
                    modifier = Modifier.padding(paddingValues)
                )
            }
        }
    }
}

