    gsrMax = 18.67,
    thermalMean = 36.4,
    thermalStd = 0.8,
    heartRateAvg = 78,
    stressLevel = "Medium"
)

private fun getSampleTimeSeriesData(): List<TimeSeriesData> {
    return (0..100).map { i ->
        TimeSeriesData(
            timestamp = System.currentTimeMillis() + i * 1000,
            gsrValue = 12.0 + 3.0 * sin(i * 0.1) + (Math.random() - 0.5) * 2.0,
            thermalValue = 36.4 + 0.5 * sin(i * 0.05) + (Math.random() - 0.5) * 0.3
        )
    }
}

