@Composable
private fun ActionButtonsCard(
    connectionState: CommandConnection.ConnectionState,
    onConnectWifi: () -> Unit,
    onTestPing: () -> Unit,
    onConnectBluetooth: () -> Unit,
    onDisconnect: () -> Unit
) {
    Card(
