                        onClick = { onActionClick(step.action) },
                        modifier = Modifier.fillMaxWidth()
                    ) {
                        Text(step.actionText)
                        Icon(
                            imageVector = Icons.AutoMirrored.Filled.OpenInNew,
                            contentDescription = "Open Link",
                            modifier = Modifier
                                .size(16.dp)
                                .padding(start = 4.dp)
                        )
                    }
                }
            }
        }
    }
}


