                                    Icon(
                                        imageVector = Icons.Default.FiberManualRecord,
                                        contentDescription = "Recording",
                                        tint = Color.Red,
                                        modifier = Modifier.size(12.dp)
                                    )
                                    Spacer(modifier = Modifier.width(4.dp))
