    data class Point(
        val position: Offset,
        val temperature: Float
    ) : ThermalAnnotation()

    data class Line(
        val start: Offset,
        val end: Offset,
        val maxTemp: Float,
        val minTemp: Float
    ) : ThermalAnnotation()

    data class Rectangle(
        val topLeft: Offset,
        val bottomRight: Offset,
        val maxTemp: Float,
        val minTemp: Float,
        val avgTemp: Float
    ) : ThermalAnnotation()
}

